//pull stars toward screen
zp=zp + 1 - t1;

//correct when below 0
zp=if( below(zp,0) , zp+2 , zp );

//darken far stars
a=(1 - zp*0.5);

zp=zp*0.7;

x_screen=xp/zp + 0.5;
y_screen=yp/zp*1.333 + 0.5;

x=x_screen;
y=y_screen;

ag=atan( (y-0.5)/(x-0.5) );

